import { useState } from 'react';
import './App.css';
import StudentForm from './components/StudentForm';
import StudentList from './components/StudentList';

function App() {
  const [students, setStudents] = useState([]);

  const handleAddStudent = (student) => {
    setStudents((prevStudents) => [...prevStudents, student]);
  };

  const handleDeleteStudent = (rollNumber) => {
    setStudents((prevStudents) => prevStudents.filter((student) => student.rollNumber !== rollNumber));
  };

  return (
    <div className="app-container">
      <div className="app-card">
        <h1>Student Management System</h1>
        <p className="subtitle">Add student records, view them in a table, and delete entries dynamically.</p>

        <StudentForm onAddStudent={handleAddStudent} />
        <StudentList students={students} onDeleteStudent={handleDeleteStudent} />
      </div>
    </div>
  );
}

export default App;
